<template>
    <div>
       <header class="header">
          <span class="sp1" @click="go()"><</span>
          <span class="sp1">登录</span>
       </header>
       <van-form>
          <van-field v-model="username" name="用户名" label="用户名" placeholder="用户名"
             :rules="[{ required: true, message: '请填写用户名' }]" /> <br>
          <!-- <el-input placeholder="请输入密码" v-model="password" show-password>

          </el-input> -->
          <input :type="flag?'password':'text'" v-model="password" placeholder="密码" @blur="shi()" /> <br>
          <!-- 组件 -->
          <zqd class="zzz" @dian="dian" :flag="flag"></zqd>

          <input type="text" placeholder="验证码" v-model="a">
          <img :src="str" alt="">
          <span @click="shua()">刷新</span>
          <div style="margin: 16px;">
             <van-button round block type="info" @click="add()" :disabled='b'>
                提交
             </van-button>
          </div>
       </van-form>

    </div>
 </template>

 <script>
     import axios from 'axios'
    import zqd from '@/components/mm'
    export default {
       data() {
          return {
             username: '',
             password: '',
             str: '',
             a: '',
             flag: false,
             b: true
          };
       },
       components: {
          zqd
       },
       created() {

       },
       mounted() {
          this.fang()
       },
       methods: {
          setCookie(key, value, t) {
             var oDate = new Date();
             oDate.setDate(oDate.getDate() + t);
             document.cookie = key + "=" + value + "; expires=" + oDate.toDateString();
          },
          add() {
             this.setCookie("cap", this.a, 2)
             this.setCookie("SID", 100, 2)
             let rem = /^1[34785]\d{9}$/
             if (rem.test(this.username) == false) {
                alert('用户输入有误')
             }
             if (this.username == "" || this.password == '') {
                alert('请输入')
                return false
             }

                axios.post('http://elm.cangdu.org/v2/login', {
                   captcha_code: this.a,
                   password: this.password,
                   username: this.username
                }).then((res) => {
                         console.log(res)
                      if(res.status==200){
                         sessionStorage.setItem('token',JSON.stringify(res.data.user_id))
                         this.$router.push('/')
                      }
                })



          },
          shua() {
             this.fang()
          },
          fang() {
             this.$http.post('http://elm.cangdu.org/v1/captchas').then((res) => {
                // console.log(res.data)
                this.str = res.data.code
             })
          },
          dian() {
             this.flag = !this.flag
          },
          shi() {
             if (this.username != "" && this.password != '') {
                this.b = false
             } else {
                this.b = true
             }
          },
          go(){
             this.$router.push('/')
          }

       }
    };
 </script>

 <style scoped>
    * {
       margin: 0;
       padding: 0;
    }

    .header {
       width: 100%;
       height: 50px;
       display: flex;
       justify-content: space-around;
       align-items: center;
       background-color: cornflowerblue;
       color: #fff;
    }

    .sp1 {
       font-size: 30px;
    }

    .zzz {
       position: absolute;
       right: 71px;
       top: 93px;
    }
 </style>